import { useContext, useEffect, useState } from "react";
import { AuthContext } from "../AuthContext";
import EventTable from "../Events/EventTable";
import "../styles/profile.css";

export default function ProfilePage() {
    const { user } = useContext(AuthContext);

    const [profile, setProfile] = useState(null);
    const [events, setEvents] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");

    const [activeTab, setActiveTab] = useState("overview");
    const [eventsView, setEventsView] = useState("upcoming");

    /* ─────────────────────────────────────────
       FETCH PROFILE + EVENTS
    ───────────────────────────────────────── */
    useEffect(() => {
        if (!user?.email) return;

        setLoading(true);

        Promise.all([
            fetch(`/api/me/profile?email=${encodeURIComponent(user.email)}`)
                .then(r => r.ok ? r.json() : Promise.reject()),
            fetch(`/api/me/events?email=${encodeURIComponent(user.email)}`)
                .then(r => r.ok ? r.json() : Promise.reject())
        ])
            .then(([profileData, eventsData]) => {
                setProfile(profileData);
                setEvents(eventsData);
                setLoading(false);
            })
            .catch(() => {
                setError("Failed to load profile");
                setLoading(false);
            });
    }, [user]);

    if (!user) {
        return <div className="profile-page">Please log in</div>;
    }

    if (loading) {
        return <div className="profile-page">Loading profile…</div>;
    }

    if (error) {
        return <div className="profile-page error">{error}</div>;
    }

    /* ─────────────────────────────────────────
       UPDATE PROFILE (TEXT)
    ───────────────────────────────────────── */
    const saveProfile = async (updates) => {
        const res = await fetch(
            `/api/me/profile?email=${encodeURIComponent(user.email)}`,
            {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(updates),
            }
        );

        if (!res.ok) throw new Error();

        const updated = await res.json();
        setProfile(updated);
        setActiveTab("overview");
    };

    return (
        <div className="profile-page">
            <ProfileHeader profile={profile} />

            {/* TABS */}
            <div className="profile-tabs">
                <TabButton label="Overview" active={activeTab === "overview"} onClick={() => setActiveTab("overview")} />
                <TabButton label="Events" active={activeTab === "events"} onClick={() => setActiveTab("events")} />
                <TabButton label="Badges" active={activeTab === "badges"} onClick={() => setActiveTab("badges")} />
                <TabButton label="Edit Profile" active={activeTab === "edit"} onClick={() => setActiveTab("edit")} />
            </div>

            {/* TAB CONTENT */}
            <div className="profile-tab-content">
                {activeTab === "overview" && <OverviewTab profile={profile} />}

                {activeTab === "events" && (
                    <EventsTab
                        events={events}
                        eventsView={eventsView}
                        setEventsView={setEventsView}
                    />
                )}

                {activeTab === "badges" && (
                    <div className="muted">Badges coming soon</div>
                )}

                {activeTab === "edit" && (
                    <EditProfileTab
                        profile={profile}
                        email={user.email}
                        onSave={saveProfile}
                        onAvatarUpdated={(updated) => {
                            setProfile(updated);
                            setActiveTab("overview");
                        }}
                    />
                )}
            </div>
        </div>
    );
}

/* ─────────────────────────────────────────
   HEADER
───────────────────────────────────────── */
function ProfileHeader({ profile }) {
    return (
        <div className="profile-header">
            <div className="profile-avatar">
                {profile.avatarUrl ? (
                    <img
                        src={profile.avatarUrl}
                        alt="avatar"
                        style={{ width: 80, borderRadius: "50%" }}
                    />
                ) : (
                    <div className="avatar-placeholder">
                        {(profile.displayName || profile.username)[0]}
                    </div>
                )}
            </div>

            <div className="profile-info">
                <h1>{profile.displayName || profile.username}</h1>
                <p className="profile-role">{profile.role}</p>

                {profile.bio && <p className="profile-bio">{profile.bio}</p>}

                <div className="profile-stats">
                    <div>
                        <strong>{profile.eventsJoined}</strong>
                        <span>Events</span>
                    </div>
                    <div>
                        <strong>{profile.participationScore}</strong>
                        <span>Score</span>
                    </div>
                </div>
            </div>
        </div>
    );
}

/* ───────────────────────────────────────── */
function OverviewTab({ profile }) {
    return <div>Welcome back, {profile.displayName || profile.username}</div>;
}

/* ───────────────────────────────────────── */
function TabButton({ label, active, onClick }) {
    return (
        <button className={`profile-tab ${active ? "active" : ""}`} onClick={onClick}>
            {label}
        </button>
    );
}

/* ─────────────────────────────────────────
   EVENTS TAB
───────────────────────────────────────── */
function EventsTab({ events, eventsView, setEventsView }) {
    const now = new Date();

    const upcoming = events.filter(e => !e.startAt || new Date(e.startAt) >= now);
    const past = events.filter(e => e.startAt && new Date(e.startAt) < now);

    const list = eventsView === "upcoming" ? upcoming : past;

    return (
        <div>
            <div className="events-subtabs">
                <button className={eventsView === "upcoming" ? "active" : ""} onClick={() => setEventsView("upcoming")}>
                    Upcoming ({upcoming.length})
                </button>
                <button className={eventsView === "past" ? "active" : ""} onClick={() => setEventsView("past")}>
                    Past ({past.length})
                </button>
            </div>

            {list.length ? (
                <EventTable events={list} showClub />
            ) : (
                <div className="muted">No events</div>
            )}
        </div>
    );
}

/* ─────────────────────────────────────────
   EDIT PROFILE TAB
───────────────────────────────────────── */
function EditProfileTab({ profile, email, onSave, onAvatarUpdated }) {
    const [form, setForm] = useState({
        displayName: profile.displayName || "",
        bio: profile.bio || "",
    });

    const [saving, setSaving] = useState(false);
    const [error, setError] = useState("");

    const submit = async (e) => {
        e.preventDefault();
        setSaving(true);
        setError("");

        try {
            await onSave(form);
        } catch {
            setError("Failed to save profile");
        } finally {
            setSaving(false);
        }
    };

    return (
        <form className="edit-profile-form" onSubmit={submit}>
            {error && <div className="error">{error}</div>}

            <label>
                Display Name
                <input
                    value={form.displayName}
                    onChange={e => setForm({ ...form, displayName: e.target.value })}
                />
            </label>

            <label>
                Bio
                <textarea
                    rows={4}
                    value={form.bio}
                    onChange={e => setForm({ ...form, bio: e.target.value })}
                />
            </label>

            <label>
                Change Avatar
                <input
                    type="file"
                    accept="image/*"
                    onChange={async (e) => {
                        const file = e.target.files[0];
                        if (!file) return;

                        const formData = new FormData();
                        formData.append("file", file);

                        const res = await fetch(
                            `/api/me/avatar?email=${encodeURIComponent(email)}`,
                            { method: "POST", body: formData }
                        );

                        if (!res.ok) {
                            alert("Avatar upload failed");
                            return;
                        }

                        const updated = await res.json();
                        onAvatarUpdated(updated);
                    }}
                />
            </label>

            <button type="submit" disabled={saving}>
                {saving ? "Saving…" : "Save Changes"}
            </button>
        </form>
    );
}
